<script lang="ts">
	import { onMount } from 'svelte'
	let { iconMap = $bindable({}) } = $props()
	const groupBy = (items, key) =>
		items.reduce(
			(result, item) => ({
				...result,
				[item[key]]: [...(result[item[key]] || []), item]
			}),
			{}
		)
	let payload = $state({
		title: 'Icon Archive',
		body: {},
		data: {}
	})
	const extractIconMap = () => {
		const symbols = document.querySelectorAll('#sprite-1 symbol')
		const iconArr = []
		symbols.forEach((symbol, id) => {
			const icon = symbol.id
			const [group, name] = icon.split(/-(.+)/)
			iconArr.push({ id, group, name, icon })
		})

		return iconArr
	}

	onMount(() => {
		iconMap = extractIconMap()
		const grouped = groupBy(iconMap, 'group')
		const slugs = Object.keys(grouped)
		const keys = Object.keys(iconMap[0])
		payload.data = grouped
		payload.body = {
			icons: iconMap,
			groups: slugs.join(', '),
			keys: keys.join(', ')
		}
		console.log(iconMap)
		// sleep(2222).then(open)
	})
</script>

